<template>
  <div>
    <Header></Header>
    <div v-if="!$auth.loading">
      <div v-if="showComponent">
        <component :is="innerComponent" v-if="$auth.isAuthenticated" :userId="$auth.user.sub" v-bind:prop="prop"></component>
        <div v-else>
          <p class="text-center fs-3 m-3">You need to be logged in to see this page</p>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import Header from './components/Header.vue'
import Feed from './components/Feed.vue'
import Question from './components/Question.vue'
import QuestionEditor from './components/QuestionEditor.vue'
import Library from './components/Library.vue'
export default {
  name: 'App',
  data() {
    return {
      innerComponent: undefined,
      showComponent: false,
      prop: undefined,
    }
  },
  components: {
    Question,
    Feed,
    Header,
    QuestionEditor,
    Library,
  },
  props: {
    //component: String,
  },
  async mounted() {
    const path = window.location.pathname.split('/')
    path.splice(0, 1)
    // console.log(path)
    switch (path[0]) {
      case '':
        this.innerComponent = 'Feed'
        break;

      case 'library':
        this.innerComponent = 'Library'
        break;

      case 'question':
          if(path[1] === 'editor') {
            this.innerComponent = 'QuestionEditor'
          } else {
            this.innerComponent = 'Question'
            this.prop = path[1]
          }
          break;

      default:
        if (window.location)
          this.innerComponent = 'Feed'
        break;
    }

    this.showComponent = true
  },
  methods: {
  },
  computed: {
    userId() {
      if (this.$auth.isAuthenticated) {
        return this.$auth.user.sub
      }
      return null
    },
  }
}
</script>